// ============================================================
// COLE AQUI A LISTA DE CONTATOS DO SEU WHATSAPP
// Formato: { nome, numero, ultimaCompra (opcional) }
// O número deve estar no formato: 5511999999999
// (55 + DDD + número, sem espaços ou símbolos)
// ============================================================

const contatos = [
  { nome: "João Silva", numero: "5511999990001", ultimaCompra: "2024-10-15" },
  { nome: "Maria Santos", numero: "5511999990002", ultimaCompra: "2024-09-20" },
  { nome: "Carlos Oliveira", numero: "5521999990003", ultimaCompra: "2024-11-01" },
  { nome: "Ana Costa", numero: "5531999990004", ultimaCompra: "2024-08-30" },
  { nome: "Pedro Lima", numero: "5541999990005", ultimaCompra: "2024-12-05" }
  // Adicione mais contatos aqui...
];

// Validação e normalização dos números
const contatosValidos = contatos
  .filter(c => c.numero && c.numero.toString().length >= 12)
  .map(c => ({
    nome: c.nome || 'Cliente',
    numero: c.numero.toString().replace(/\D/g, ''),
    ultimaCompra: c.ultimaCompra || null,
    numeroFormatado: c.numero.toString().replace(/\D/g, '') + '@s.whatsapp.net'
  }));

console.log(`✅ ${contatosValidos.length} contatos válidos carregados`);

return contatosValidos.map(c => ({ json: c }));

// Filtra contatos que ainda NÃO receberam mensagem
const todosContatos = $input.all();
const redisResult = $('Verificar Já Enviados (Redis)').first();

let jaEnviados = [];
try {
  const raw = redisResult?.json?.enviados || redisResult?.json?.value || null;
  if (raw) {
    jaEnviados = typeof raw === 'string' ? JSON.parse(raw) : raw;
  }
} catch(e) {
  jaEnviados = [];
}

console.log(`📊 Já enviados: ${jaEnviados.length}`);

const pendentes = todosContatos.filter(item => {
  return !jaEnviados.includes(item.json.numero);
});

console.log(`📬 Pendentes para envio: ${pendentes.length}`);

if (pendentes.length === 0) {
  console.log('✅ Todos os contatos já foram contactados nesta campanha!');
  return [];
}

// Limita por rodada para não sobrecarregar
const limite = $('Parâmetros Campanha').item.json.limitePorRodada || 30;
const lote = pendentes.slice(0, limite);

console.log(`🚀 Enviando lote de ${lote.length} contatos`);

return lote;

// Verifica horário comercial para não enviar em horários ruins
const agora = new Date();
// Ajusta para horário de Brasília (UTC-3)
const horasBrasilia = new Date(agora.getTime() - 3 * 60 * 60 * 1000);
const hora = horasBrasilia.getUTCHours();
const diaSemana = horasBrasilia.getUTCDay(); // 0=dom, 6=sab

// Só envia entre 9h e 20h, de segunda a sábado
const horarioOk = hora >= 9 && hora < 20;
const diaOk = diaSemana >= 1 && diaSemana <= 6;

if (!horarioOk || !diaOk) {
  console.log(`⏰ Fora do horário comercial. Hora: ${hora}h, Dia: ${diaSemana}. Pulando...`);
  return [];
}

// Gera delay aleatório humanizado
const parametros = $('Parâmetros Campanha').item.json;
const delayMin = parametros.delayMinimoSegundos || 45;
const delayMax = parametros.delayMaximoSegundos || 120;
const delaySeg = Math.floor(Math.random() * (delayMax - delayMin + 1)) + delayMin;

const item = $input.first();

return [{
  json: {
    ...item.json,
    delaySeg,
    horaEnvio: horasBrasilia.toISOString()
  }
}];

// Gera a mensagem personalizada de reativação
// Adapte o texto conforme sua marca/produto

const item = $input.first().json;
const nome = item.nome ? item.nome.split(' ')[0] : 'cliente';

// Variações de mensagem para evitar padrão (reduz risco de spam)
const variacoes = [
  `Olá ${nome}! 👋 Tudo bem?\n\nSou da equipe LM Smartwatch e vi que faz um tempinho que não conversamos.\n\nTemos novidades incríveis que acho que você vai amar! Posso te mostrar? 😊`,

  `Oi ${nome}! 😊\n\nPassando aqui rapidinho da LM Smartwatch...\n\nTemos algumas ofertas exclusivas essa semana que separei especialmente pra você! Quer dar uma olhada?`,

  `${nome}, olá! 🤝\n\nAqui é da LM Smartwatch. Faz um tempo que não nos falamos!\n\nTemos um mimo especial para clientes que já compraram com a gente. Posso te contar mais?`,

  `Oi ${nome}! Tudo certo? 👋\n\nSou da LM Smartwatch e queria saber se posso te ajudar com algo.\n\nTemos lançamentos novos que podem te interessar! 🕐✨`
];

// Escolhe variação baseada no número do telefone (consistente por contato)
const idx = parseInt(item.numero.slice(-1)) % variacoes.length;
const mensagem = variacoes[idx];

return [{
  json: {
    ...item,
    mensagemTexto: mensagem,
    variacaoUsada: idx
  }
}];

// Registra o envio bem-sucedido no Redis
// Isso evita reenvio em futuras execuções

const numero = $('Validar Horário + Delay Aleatório').item.json.numero;
const campanhaId = $('Parâmetros Campanha').item.json.campanhaId;
const chaveRedis = `${campanhaId}_enviados`;

return [{
  json: {
    numero,
    campanhaId,
    chaveRedis,
    timestamp: new Date().toISOString(),
    status: 'enviado'
  }
}];

// Log de falha — registra para análise posterior
const item = $('Validar Horário + Delay Aleatório').item.json;
console.error(`❌ Falha ao enviar para ${item.numero} (${item.nome})`);

return [{
  json: {
    numero: item.numero,
    nome: item.nome,
    status: 'falha',
    timestamp: new Date().toISOString(),
    motivo: 'Evolution API não confirmou envio'
  }
}];

// Relatório final da rodada
const campanhaId = $('Parâmetros Campanha').item.json.campanhaId;
console.log(`📊 Rodada concluída para campanha: ${campanhaId}`);
console.log(`🔄 Próxima rodada em breve conforme agendamento...`);

return [{
  json: {
    status: 'rodada_concluida',
    campanhaId,
    timestamp: new Date().toISOString()
  }
}];
